int N, A, B;
bool used[100];
int rings[100];
vector<int> G[100];

int rec(int pos) {
    if (used[pos]) return 0;
    used[pos] = true;
    int ret = 1;

    for (int i = 0; i < rings[pos]; i++) {
        ret = max(ret, rec(G[pos][i]) + 1);
    }

    used[pos] = false;

    return ret;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    while (true) {
        scanf("%d", &N);

        if (N == 0) { break; }

        for (int i = 0; i < 100; i++) {
            used[i] = false;
            rings[i] = 0;
            G[i].clear();
        }

        for (int i = 0; i < N; i++) {
            scanf("%d", &A); A--;
            scanf("%d", &B); B--;

            G[A].push_back(B);
            G[B].push_back(A);
        }

        for (int i = 0; i < 100; i++) {
            rings[i] = G[i].size();
        }

        int nodes = 0;

        for (int i = 0; i < 100; i++) {
            if (rings[i]) {
                nodes++;
            }
        }

        int ret = 0;

        for (int i = 0; i < 100; i++) {
            ret = max(ret, rec(i));

            if (ret == nodes) { break; }
        }

        printf("%d\n", ret);
    }

    return 0;
}

